def strip(poly):
    while poly and poly[-1] == 0:
        poly.pop()
    return poly


def first_coef_to_1(poly, n):
    x = pow(poly[-1], -1, n)
    new_poly = []
    for i in poly:
        value = i * x
        value = value % n
        new_poly.append(value)
    return strip(new_poly)


def polynomial_longdiv(p1, p2, n):
    p1 = p1[:]
    quot = [0] * max(0, len(p1) - len(p2) + 1)
    lead_inv = pow(p2[-1], -1, n)

    while len(p1) >= len(p2):
        coeff = (p1[-1] * lead_inv) % n
        idx = len(p1) - len(p2)
        quot[idx] = coeff

        for j in range(len(p2)):
            p1[idx + j] = (p1[idx + j] - coeff * p2[j]) % n

        strip(p1)

    return strip(quot), p1


def polynomial_gcd(f, g, n):
    f = first_coef_to_1(strip(f), n)
    g = first_coef_to_1(strip(g), n)

    while g:
        quotient, r = polynomial_longdiv(f, g, n)
        f = g
        g = strip(r)

    return first_coef_to_1(strip(f), n)


f1 = []
for i in range(e + 1):
    first_part = comb(e, i)
    second_part = pow(a1, i, n)
    third_part = pow(b1, e - i, n)
    value = first_part * second_part * third_part
    value = value % n
    f1.append(value)
f1[0] = (f1[0] - c1) % n

f2 = []
for i in range(e + 1):
    first_part = comb(e, i)
    second_part = pow(a2, i, n)
    third_part = pow(b2, e - i, n)
    value = first_part * second_part * third_part
    value = value % n
    f2.append(value)
f2[0] = (f2[0] - c2) % n

g = polynomial_gcd(f1, f2, n)
m = (-g[0]) % n

flag = long_to_bytes(int(m))
print(flag)
